import collections

def pagerank(graph, damping_factor=0.85, iterations=100):
    all_pages = set()
    for source, targets in graph.items():
        all_pages.add(source)
        for target in targets:
            all_pages.add(target)

    pages = sorted(list(all_pages))
    N = len(pages)

    if N == 0:
        return {}

    pagerank_scores = {page: 1.0 / N for page in pages}

    out_degrees = {page: len(graph.get(page, [])) for page in pages}

    incoming_links = collections.defaultdict(list)
    for source, targets in graph.items():
        for target in targets:
            incoming_links[target].append(source)

    for _ in range(iterations):
        new_pagerank_scores = {}
        dangling_pagerank_sum = 0.0
        for page in pages:
            if out_degrees[page] == 0:
                dangling_pagerank_sum += pagerank_scores[page]

        for page in pages:
            teleport_term = (1.0 - damping_factor) / N
            dangling_term = damping_factor * dangling_pagerank_sum / N

            link_contribution_sum = 0.0
            for incoming_page in incoming_links[page]:
                if out_degrees[incoming_page] > 0:
                    link_contribution_sum += pagerank_scores[incoming_page] / out_degrees[incoming_page]

            new_pagerank_scores[page] = teleport_term + dangling_term + damping_factor * link_contribution_sum

        pagerank_scores = new_pagerank_scores

    return pagerank_scores

if __name__ == '__main__':
    # Örnek Kullanım:
    # A -> B, C
    # B -> C
    # C -> A
    # D (dangling node)
    # E -> D
    graph1 = {
        'A': ['B', 'C'],
        'B': ['C'],
        'C': ['A'],
        'D': [], # Dangler node
        'E': ['D']
    }

    pr1 = pagerank(graph1, damping_factor=0.85, iterations=100)
    print("Graph 1 PageRank:", pr1)

    graph2 = {
        'Page1': ['Page2', 'Page3'],
        'Page2': ['Page1'],
        'Page3': ['Page2'],
    }

    pr2 = pagerank(graph2, damping_factor=0.85, iterations=100)
    print("Graph 2 PageRank:", pr2)

